class LmdbCascadesContextPropagationTest {

	@Test
	void minusRightSubtreeJoinOrderReceivesLeftAssuredBindings() {
		String previousMode = System.setProperty(LmdbCascadesOptimizer.MODE_PROPERTY, "exact");
		try {
			RecordingJoinOrderStatistics statistics = new RecordingJoinOrderStatistics();
			StatementPattern left = new StatementPattern(new Var("person"), new Var("leftPredicate"),
					new Var("leftValue"));
			Join right = new Join(new StatementPattern(new Var("person"), new Var("minusPredicate"), new Var("event")),
					new StatementPattern(new Var("event"), new Var("eventPredicate"), new Var("date")));
			QueryRoot root = new QueryRoot(new Difference(left, right));

			new LmdbCascadesOptimizer(statistics, false).optimize(root, null, EmptyBindingSet.getInstance());

			assertTrue(statistics.calls.stream().anyMatch(JoinOrderCall::minusRightJoinBoundToPerson),
					"MINUS RHS subtree planning should preserve the left-bound shared variable: "
							+ statistics.calls);
		} finally {
			restoreMode(previousMode);
		}
	}

	private static void restoreMode(String previousMode) {
		if (previousMode == null) {
			System.clearProperty(LmdbCascadesOptimizer.MODE_PROPERTY);
		} else {
			System.setProperty(LmdbCascadesOptimizer.MODE_PROPERTY, previousMode);
		}
	}

	private record JoinOrderCall(Set<String> initiallyBoundVars, List<Set<String>> argBindingNames) {
		private boolean minusRightJoinBoundToPerson() {
			return initiallyBoundVars.contains("person")
					&& argBindingNames.contains(Set.of("person", "minusPredicate", "event"))
					&& argBindingNames.contains(Set.of("event", "eventPredicate", "date"));
		}
	}

	private static final class RecordingJoinOrderStatistics extends EvaluationStatistics implements JoinOrderPlanner {
		private final List<JoinOrderCall> calls = new ArrayList<>();

		@Override
		public Optional<JoinOrderPlan> planJoinOrder(List<TupleExpr> args, Set<String> initiallyBoundVars,
				Algorithm algorithm) {
			List<Set<String>> argBindingNames = args.stream()
					.map(arg -> Set.copyOf(arg.getBindingNames()))
					.toList();
			this.calls.add(new JoinOrderCall(initiallyBoundVars == null ? Set.of() : Set.copyOf(initiallyBoundVars),
					argBindingNames));
			return Optional.of(new JoinOrderPlan(args, 10.0d, 50.0d, List.of(), Map.of(), Map.of(), List.of()));
		}
	}
}
